#include <stdio.h>
#include <stdlib.h>

int main() {
    int *x;

    /* dinamicka alokacija jedne int varijable */
    x = (int *)malloc(sizeof(int));

    if (x == NULL) {
        printf("Alokacija nije uspjela.\n");
        return 1;
    }

    printf("Unesite cijeli broj: ");
    scanf("%d", x);

    printf("Uneseni broj je: %d\n", *x);

    /* oslobadjanje memorije */
    free(x);

    return 0;
}
